import heapq
import sys

class Solution:
    def __init__(self):
        self.min_heap = []

    def insert(self, val: int) -> None:
        heapq.heappush(self.min_heap, val)

    def removeMin(self) -> int:
        if self.isEmpty():
            return -1
        return heapq.heappop(self.min_heap)

    def getMin(self) -> int:
        if self.isEmpty():
            return -1
        return self.min_heap[0]

    def isEmpty(self) -> bool:
        return len(self.min_heap) == 0

    def size(self) -> int:
        return len(self.min_heap)

if __name__ == '__main__':
    sol = Solution()
    n = int(sys.stdin.readline().strip())
    for _ in range(n):
        op, *val = sys.stdin.readline().strip().split()
        if op == 'insert':
            sol.insert(int(val[0]))
