#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
private:
    priority_queue<int, vector<int>, greater<int>> min_heap;
public:
    void insert(int val) {
        min_heap.push(val);
    }

    int removeMin() {
        if (isEmpty()) {
            return -1;
        }
        int val = min_heap.top();
        min_heap.pop();
        return val;
    }

    int getMin() {
        if (isEmpty()) {
            return -1;
        }
        return min_heap.top();
    }

    bool isEmpty() {
        return min_heap.empty();
    }

    int size() {
        return min_heap.size();
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    Solution sol;
    int n;
    cin >> n;
    for (int i = 0; i < n; i++) {
        string op;
        cin >> op;
        if (op == "insert") {
            int val;
            cin >> val;
            sol.insert(val);
        } else if (op == "removeMin") {
            cout << sol.removeMin() << '\n';
        } else if (op == "getMin") {
            cout << sol.getMin() << '\n';
        } else if (op == "isEmpty") {
            cout << (sol.isEmpty() ? "true" : "false") << '\n';
        } else if (op == "size") {
            cout << sol.size() << '\n';
        }
    }
    return 0;
}
